<?php
require_once __DIR__.'/app/classes/BaseDeDonnees.php'; require_once __DIR__.'/app/classes/Session.php'; require_once __DIR__.'/app/helpers.php';
$u=current_user(); $db=db();
$cours=$db->query('SELECT c.*, p.nom promotion, GROUP_CONCAT(u.nom SEPARATOR ", ") enseignants FROM cours c JOIN promotions p ON p.id=c.promotion_id LEFT JOIN enseignement e ON e.cours_id=c.id LEFT JOIN users u ON u.id=e.user_id GROUP BY c.id ORDER BY c.nom')->fetchAll();
$etudiants=[]; if(in_array($u['role'],['enseignant','assistant'],true)){ $st=$db->prepare('SELECT c.nom cours, us.nom etudiant, us.identifiant FROM enseignement e JOIN cours c ON c.id=e.cours_id JOIN inscriptions i ON i.cours_id=c.id JOIN users us ON us.id=i.user_id WHERE e.user_id=? ORDER BY c.nom, us.nom'); $st->execute([$u['id']]); $etudiants=$st->fetchAll(); }
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Cours</title><link rel="stylesheet" href="assets/css/style.css"></head><body><aside class="sidebar"><div class="brand small"><div class="logo">📚</div><div><h2>Cours</h2><p><?=h(role_label($u['role']))?></p></div></div><nav><a href="dashboard.php">💬 Messages</a><a class="active" href="cours.php">📚 Cours</a><a href="valve.php">📣 Valve</a></nav></aside><main class="content page"><h1>📚 Cours et promotions</h1><div class="grid"><?php foreach($cours as $c): ?><div class="card"><h2><?=h($c['nom'])?></h2><p><?=h($c['description'])?></p><p><b>Promotion :</b> <?=h($c['promotion'])?></p><p><b>Enseignants :</b> <?=h($c['enseignants'] ?: 'Non affecté')?></p><a class="btn" href="chat.php?type=public&cours_id=<?=$c['id']?>">Ouvrir le mur</a></div><?php endforeach; ?></div><?php if($etudiants): ?><h2>👨‍🎓 Étudiants affiliés à mes cours</h2><table><?php foreach($etudiants as $e): ?><tr><td><?=h($e['cours'])?></td><td><?=h($e['etudiant'])?></td><td><?=h($e['identifiant'])?></td></tr><?php endforeach; ?></table><?php endif; ?></main></body></html>
